import React from 'react';
import axios from 'axios';

function Login(){
 const login=()=>{
  axios.post('http://localhost:8080/api/auth/login')
  .then(res=>{
   localStorage.setItem('token',res.data);
  });
 };
 return <button onClick={login}>Login</button>;
}
export default Login;
